const items = $input.all();
const byName = {};
for (const it of items) {
  const name = it.pairedItem && it.pairedItem.node
    ? it.pairedItem.node
    : (it.json && it.json.__nodeName) || 'unknown';
  byName[name] = it.json;
}

function pick(nodeNames) {
  for (const n of nodeNames) {
    if (byName[n]) return byName[n];
  }
  // fallback: scan by URL in request
  for (const it of items) {
    const j = it.json || {};
    return j;
  }
  return {};
}

const briefRaw = $('GET decision-brief').first().json;
const edgeRaw = $('GET sourcea.app health').first().json;
const fbeRaw = $('GET FBE runner health').first().json;

const briefStatus = Number(briefRaw.statusCode || briefRaw.status || 0);
const briefBody = String(briefRaw.data || briefRaw.body || briefRaw || '');
const hasDecisionTitle =
  /Vendor Decision Brief/i.test(briefBody) ||
  /<title>[^<]*Decision Brief/i.test(briefBody) ||
  /Choose a vendor with a brief you can defend/i.test(briefBody);
const looksLikeHome =
  /Proof-backed MVPs and acquisition systems/i.test(briefBody) &&
  !hasDecisionTitle;

const edgeBody = edgeRaw.body || edgeRaw.data || edgeRaw;
const edgeOk =
  Number(edgeRaw.statusCode || edgeRaw.status || 0) === 200 &&
  (edgeBody.ok === true || (typeof edgeBody === 'object' && edgeBody.ok));

const fbeBody = fbeRaw.body || fbeRaw.data || fbeRaw;
const fbeOk =
  Number(fbeRaw.statusCode || fbeRaw.status || 0) === 200 &&
  (fbeBody.ok === true || (typeof fbeBody === 'object' && fbeBody.ok));

const briefOk = briefStatus === 200 && hasDecisionTitle && !looksLikeHome;
const terminal = briefOk && edgeOk && fbeOk ? 'ACCEPTED_ARTIFACT' : 'BOUNDED_FAILURE';
const blockers = [];
if (!briefOk) {
  blockers.push(
    looksLikeHome
      ? 'decision_brief_serving_homepage'
      : briefStatus !== 200
        ? 'decision_brief_http_' + briefStatus
        : 'decision_brief_missing_title'
  );
}
if (!edgeOk) blockers.push('sourcea_app_health_fail');
if (!fbeOk) blockers.push('fbe_runner_health_fail');

return [
  {
    json: {
      schema: 'sourcea-n8n-decision-brief-health-wire-v1',
      at: new Date().toISOString(),
      terminal,
      ok: terminal === 'ACCEPTED_ARTIFACT',
      checks: {
        decision_brief: {
          url: 'https://sourcea.app/decision-brief',
          status: briefStatus,
          has_decision_title: hasDecisionTitle,
          looks_like_homepage: looksLikeHome,
          ok: briefOk,
        },
        sourcea_app_health: {
          url: 'https://sourcea.app/health',
          ok: edgeOk,
          body: typeof edgeBody === 'object' ? edgeBody : { raw: String(edgeBody).slice(0, 200) },
        },
        fbe_runner_health: {
          url: 'https://sourcea-fbe-runner-production.up.railway.app/health',
          ok: fbeOk,
          body: typeof fbeBody === 'object' ? fbeBody : { raw: String(fbeBody).slice(0, 200) },
        },
      },
      blockers,
      for_founder: {
        show_this:
          terminal === 'ACCEPTED_ARTIFACT'
            ? 'PASS — Decision Brief live + edge + FBE healthy'
            : 'FAIL — ' + blockers.join(' · ') + ' · fix Cloudflare Pages publish for /decision-brief',
      },
      wired_to: {
        n8n_cloud: 'https://noetfield.app.n8n.cloud',
        product: 'https://sourcea.app/decision-brief',
        law: 'contracts define goal · machines control · verifiers decide',
      },
    },
  },
];
